#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
const int MX=1e7+5,N=2e6+5;
using namespace std;
struct Seg{int l,r,sum;}t[MX];int cnt;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res;
}
inline void print(int p){if(p<0)putchar('-'),p=-p;if(p>9)print(p/10);putchar(p%10+'0');}
inline void build(int l,int r,int &cur)
{
	int mid=(l+r)>>1;cur=++cnt;if(l==r)return;
	build(l,mid,t[cur].l);build(mid+1,r,t[cur].r);
}
int a[N],q[N],Rt[N];
inline void ins(int cur,int loc,int &x,int l,int r)
{
	t[x=++cnt]=t[cur];int mid=(l+r)>>1;t[x].sum++;if(l==r)return;
	if(loc<=mid)ins(t[cur].l,loc,t[x].l,l,mid);
	else ins(t[cur].r,loc,t[x].r,mid+1,r);
}
inline int Query(int x,int y,int l,int r,int k)
{
	
	if(l==r)return a[l];
	int dl=t[t[y].l].sum-t[t[x].l].sum,mid=(l+r)>>1;
//	printf("%d %d %d %d %d\n",x,y,dl,k,l);
	if(k<=dl)return Query(t[x].l,t[y].l,l,mid,k);
	return Query(t[x].r,t[y].r,mid+1,r,k-dl);
}
int main()
{
	int qn=read(),m=read();rep(1,qn,i)a[i]=q[i]=read();
	sort(a+1,a+qn+1);int n=unique(a+1,a+qn+1)-a-1;build(1,n,Rt[0]);
	rep(1,qn,i){int l=1,r=n,mid,loc;while(l<=r)(a[mid=(l+r)>>1]>q[i])?r=mid-1:(l=mid+1,loc=mid);ins(Rt[i-1],loc,Rt[i],1,n);}
	rep(1,m,i){int l=read(),r=read(),k=read();print(Query(Rt[l-1],Rt[r],1,n,k));puts("");}
//	printf("%d\n",cnt);rep(1,cnt,i)printf("%d : %d %d %d\n",i,t[i].l,t[i].r,t[i].sum);printf("%d %d\n",Rt[1],Rt[2]);
}
